import React, {
    useState,
    createContext,
    useMemo,
    useRef,
    useEffect,
} from "react";
import { Link } from "react-router-dom";
import "react-datepicker/dist/react-datepicker.css";
import Toggle from "react-toggle";
import "react-toggle/style.css";
import Randomstring from "randomstring";
import GoogleMapReact from "google-map-react";
import moment from "moment";
import { useNavigate } from "react-router-dom";
import { Nav, Container, Modal, FormControl, Row, Col } from "react-bootstrap";
import { useTranslation } from "react-i18next";
import { Header } from "../../layout/header";
import AutoComplete from "./Autocomplete";
import LocationCheck from "../../../images/location-check.png";
import Trash from "../../../images/trash.png";
import "./Home.scss";
import { useDispatch, useSelector } from "react-redux";
import {
    select_booking,
    save_temp_booking,
} from "../../../redux/actions/BookingstateActions";
import axios from "axios";
import Status_board from "../../layout/Status_board";
import { DatePicker } from "@y0c/react-datepicker";
import DateTimePicker from 'react-datetime-picker';
import "@y0c/react-datepicker/assets/styles/calendar.scss";
import dayjs from "dayjs";
export const UserContext = createContext();
const Home = () => {
    const temp = useSelector((state) => state.bookingState.temp_booking);
    console.log('temp', temp)
    const [selectedOption, setSelectedOption] = useState(temp.pick_location);
    const [startDate, setStartDate] = useState(temp.pickup_date);
    const [isSwitchOn, setIsSwitchOn] = useState(temp.isSwitchOn);
    const [stopNum, setStopNum] = useState([{ id: Randomstring.generate(10) }]);
    const [modalShow, setModalShow] = useState(false);
    const [passenger, setPassenger] = useState(
        temp.passenger ? temp.passenger : 3
    );
    const [value, onChange] = useState(new Date());
    const [children, setChildren] = useState(temp.children ? temp.children : 3);
    const [bag, setBag] = useState(temp.bags ? temp.bags : 3);
    const [key, setKey] = useState("searchall");
    const [key2, setKey2] = useState("searchall2");
    const [stopFields, setStopFields] = useState(
        [{
            id: 0,
            children: {
                searchall: true,
                address: "",
                airport: "",
                landmark: ""
            }
        }]
    )
    const [stopVisible, setStopVisible] = useState(false)
    const [stopKey, setStopKey] = useState('searchall')
    const [methodkey, setMethodKey] = useState(1);
    const [startTime, setStartTime] = useState(temp.pickup_time);
    const [dropoff, setDropoff] = useState(temp.dropoff_location);
    const [stop, setStop] = useState([]);
    const [mapInstance, setMapInstance] = useState();
    const [mapApi, setMapApi] = useState();
    const [dropoffAddress, setDropoffAddress] = useState();
    const [pickupAddress, setPickupAddress] = useState();

    console.log('keeeyy', key)
    useEffect(() => {
        temp.pickup_date
            ? setStartDate(temp.pickup_date)
            : setStartDate(moment(new Date()));
        temp.pickup_time
            ? setStartTime(temp.pickup_time)
            : setStartTime(moment(new Date()));
        setSelectedOption(temp.pick_location);
        setIsSwitchOn(temp.isSwitchOn);
        temp.passenger ? setPassenger(temp.passenger) : setPassenger(0);
        temp.passenger ? setChildren(temp.children) : setChildren(0);
        temp.methodKey ? setMethodKey(temp.methodKey) : setMethodKey(1);
        setDropoff(temp.dropoff_location);
        temp.bags ? setBag(temp.bags) : setBag(0);
        temp.stop ? setStop(temp.stop) : setStop([]);
        temp.stopNum
            ? setStopNum(temp.stopNum)
            : setStopNum([{ id: Randomstring.generate(10) }]);
        setMins(temp.mins);
        setHours(temp.hours);
    }, []);

    const datePickerRef = useRef();
    const [errors, setErrors] = useState({
        pickup: "",
        dropoff: "",
        mins: "",
        hours: "",
        startDate: "",
        startTime: "",
    });
    const handleSUbmit = () => {
        debugger;
        const validationErrors = {};
        let error = validate(selectedOption);
        if (error && error.length > 0) validationErrors["pickup"] = error;
        error = validate(dropoff);
        if (error && error.length > 0) validationErrors["dropoff"] = error;
        error = validate(startDate);
        if (error && error.length > 0 && !isSwitchOn)
            validationErrors["startDate"] = error;
        error = validate(startTime);
        ;
        if (error && error.length > 0 && !isSwitchOn)
            validationErrors["startTime"] = error;
        error = validate(mins);
        if (error && error.length > 0 && methodkey == 2)
            validationErrors["mins"] = error;
        error = validate(hours);
        if (error && error.length > 0 && methodkey == 2)
            validationErrors["hours"] = error;

        if (Object.keys(validationErrors).length > 0) {
            setErrors(validationErrors);
            //console.log(validationErrors)
        } else select_vehicle();
        select_vehicle();
    };
    let navigate = useNavigate();
    const validate = (value) => {
        if (!value) return "Field is Required";
        else return "";
    };

    const { t } = useTranslation();
    const _onClick = (value) => {
        // setLat(value.lat)
        // setLng(value.lng)
    };
    const setCurrentLocation = () => {
        if ("geolocation" in navigator) {
            navigator.geolocation.getCurrentPosition((position) => {
                setCenter([position.coords.latitude, position.coords.longitude]);
            });
        }
    };
    const apiHasLoaded = (map, maps) => {
        setMapapitLoaded(true);
        setMapApi(maps);
        setMapInstance(map);
        _generateAddress();
    };
    const switch_onChange_handle = () => {
        setIsSwitchOn(!isSwitchOn);
    };
    const updateStop = (rowId, data) => {
        stop.filter(function (value, index, arr) {
            //Row to update
            if (value.id == rowId) {
                return { address: data };
            } else {
                return { ...value };
            }
        });
        setStop([]);
    };

    const addStop = () => {
        setStopNum([...stopNum, { id: Randomstring.generate(10) }]);
    };

    const deleteStop = (index) => {
        debugger;
        if (stopFields.length > 1) {
            setStopFields([
                ...stopFields.slice(0, index),
                ...stopFields.slice(index + 1, stopFields.length)
            ]);
        } else {
            setStopVisible(false)
        }
    };
    const _generatePickupAddress = (id) => {
        if (mapApi) {
            const geocoder = new mapApi.Geocoder();

            geocoder.geocode(
                { location: { lat: pickuplat, lng: pickuplng } },
                (results, status) => {
                    if (status === "OK") {
                        if (results[0]) {
                            setZoom(10);
                            setPickupAddress(results[0].formatted_address);
                        } else {
                            window.alert("No results found");
                        }
                    } else {
                        window.alert("Geocoder failed due to: " + status);
                    }
                }
            );
        }
    };
    const _generateDropoffAddress = (id) => {
        if (mapApi) {
            const geocoder = new mapApi.Geocoder();

            geocoder.geocode(
                { location: { lat: dropofflat, lng: dropofflng } },
                (results, status) => {
                    if (status === "OK") {
                        if (results[0]) {
                            setZoom(10);
                            setDropoffAddress(results[0].formatted_address);
                        } else {
                            window.alert("No results found");
                        }
                    } else {
                        window.alert("Geocoder failed due to: " + status);
                    }
                }
            );
        }
    };
    const _generateAddress = (id) => {
        if (mapApi) {
            const geocoder = new mapApi.Geocoder();

            geocoder.geocode(
                { location: { lat: pickuplat, lng: pickuplng } },
                (results, status) => {
                    if (status === "OK") {
                        if (results[0]) {
                            setZoom(10);
                            setPickupAddress(results[0].formatted_address);
                        } else {
                            window.alert("No results found");
                        }
                    } else {
                        window.alert("Geocoder failed due to: " + status);
                    }
                }
            );
        }
    };
    const onMarkerInteraction = (childKey, childProps, mouse) => {
        // setLat(mouse.lat);
        // setLng(mouse.lng);
        setDraggable(false);
    };
    const onMarkerInteractionMouseUp = (childKey, childProps, mouse) => { };

    const _onChange = ({ center, zoom }) => {
        setCenter(center);
        setZoom(zoom);
    };

    const [center, setCenter] = useState([]);
    const [draggable, setDraggable] = useState(true);
    const [pickuplat, setPickupLat] = useState();
    const [dropofflat, setDropoffLat] = useState();
    const [pickuplng, setPickupLng] = useState();
    const [dropofflng, setDropoffLng] = useState();
    const [stopplace, setStopPlace] = useState([]);
    const [zoom, setZoom] = useState();
    const [mapApiLoaded, setMapapitLoaded] = useState(false);

    const addPickupPlace = (place) => {
        setPickupLat(place.geometry.location.lat());
        setPickupLng(place.geometry.location.lng());
        _generatePickupAddress();
    };
    const addDropoffPlace = (place) => {
        setDropoffLat(place.geometry.location.lat());
        setDropoffLng(place.geometry.location.lng());
        _generateDropoffAddress();
    };
    const addStopPlace = (place) => {
        setStopPlace([
            ...stopplace,
            {
                lat: place.geometry.location.lat(),
                lng: place.geometry.location.lng(),
            },
        ]);
        _generateAddress();
    };
    const booking = useSelector((state) => state.bookingState);
    const login_status = useSelector((state) => state.userState.login_status);
    const dispatch = useDispatch();
    const select_vehicle = () => {
        let temp_booking = {};
        temp_booking.pickup_date = startDate;
        temp_booking.pickup_time = startTime;

        temp_booking.pick_location = selectedOption;
        temp_booking.passenger = passenger;
        temp_booking.children = children;
        temp_booking.bags = bag;
        temp_booking.trip_duration_hour = hours;
        temp_booking.trip_duration_min = mins;
        temp_booking.key = key;
        temp_booking.booking_type_id = methodkey;
        temp_booking.dropoff_location = dropoff;
        temp_booking.stop = stop;
        temp_booking.isSwitchOn = isSwitchOn;
        temp_booking.stopNum = stopNum;
        dispatch(save_temp_booking(temp_booking));
        ;
        navigate("/vehicles");
    };
    useEffect(() => {
        _generateDropoffAddress();
    }, [dropofflat, dropofflng]);
    useEffect(() => {
        _generatePickupAddress();
    }, [pickuplat, pickuplng]);
    const [hours, setHours] = useState(0);
    const [mins, setMins] = useState(20);
    useEffect(() => {
        setCurrentLocation();
    }, []);
    const weekday = ["Sun", "Mon", "Tues", "Wed", "Thur", "Fri", "Sat"];
    const monthNames = [
        "January",
        "February",
        "March",
        "April",
        "May",
        "June",
        "July",
        "August",
        "September",
        "October",
        "November",
        "December",
    ];
    const getStartDate = (date) => {
        let day = date.getDay();
        day = weekday[day];
        let month = date.getMonth();
        month = monthNames[month];
        const exactdate = date.getDate();
        const year = date.getFullYear();
        const startDate = day + ", " + month + ", " + exactdate + ", " + year;
        return startDate;
    };
    const datechange = (nowdate) => {
        const startDate = dayjs(nowdate);
        setStartDate(startDate);
    };
    const timechange = (time) => {
        setStartTime(dayjs(time));
    };
    const inputTimeChange = (e) => {
        setStartTime(e.target.value);
    };
    useEffect(() => {
        if (login_status) {
            axios
                .get(`${process.env.REACT_APP_API_BASE_URL}/booking/get`)
                .then((res) => {
                    dispatch(select_booking(res.data));
                });
        }
    }, [login_status]);

    // const handleFormChange = (index, event) => {
    //     let data = [...inputFields];
    //     data[index][event.target.name] = event.target.value;
    //     setInputFields(data);
    // }

    const setNewStop = (type, index) => {
        const updatedStop = stopFields.map((stop, i) => {
            if (i === index) {

                Object.keys(stop.children).forEach(v => {

                    if (v == type) {
                        stop.children[v] = true
                    } else {
                        stop.children[v] = false
                    }
                })
                return stop;
                //   retur n stop;
            } else {
                return stop;
            }
        });
        // stopFields[index][type] = true
        setStopFields(updatedStop)
    }
    const addFields = (stops) => {
        debugger;
        if (stopFields.length > 0 && stopVisible) {
            stops.map((stop) => {
                let id = stop.id
                let newfield = {
                    id: id + 1,
                    children: {
                        searchall: true,
                        address: "",
                        airport: "",
                        landmark: ""
                    }
                }
                setStopFields([...stopFields, newfield])
            })
        } else {
            setStopVisible(true);
        }


    }

    const callback = (selectedtype) => {
        setKey(selectedtype)
    }



    return (
        <div className="home">
            <Header />
            <div className="main">
                <Container>
                    <Status_board />
                    <div className="google-map">
                        <GoogleMapReact
                            center={center ? center : [0, 0]}
                            zoom={zoom ? zoom : 6}
                            draggable={true}
                            onChange={_onChange}
                            onChildMouseDown={onMarkerInteraction}
                            onChildMouseUp={onMarkerInteractionMouseUp}
                            onChildMouseMove={onMarkerInteraction}
                            onClick={_onClick}
                            styles={[
                                {
                                    featureType: "water",
                                    stylers: [{ color: "#46bcec" }, { visibility: "on" }],
                                },
                                { featureType: "landscape", stylers: [{ color: "#f2f2f2" }] },
                                {
                                    featureType: "road",
                                    stylers: [{ saturation: -100 }, { lightness: 45 }],
                                },
                                {
                                    featureType: "road.highway",
                                    stylers: [{ visibility: "simplified" }],
                                },
                                {
                                    featureType: "road.arterial",
                                    elementType: "labels.icon",
                                    stylers: [{ visibility: "off" }],
                                },
                                {
                                    featureType: "administrative",
                                    elementType: "labels.text.fill",
                                    stylers: [{ color: "#444444" }],
                                },
                                { featureType: "transit", stylers: [{ visibility: "off" }] },
                                { featureType: "poi", stylers: [{ visibility: "off" }] },
                            ]}
                            bootstrapURLKeys={{
                                key: "AIzaSyAygoWDQ-IvoehtL-nJ0qVcHnUkVLsN6Ps",
                                libraries: ["places", "geometry"],
                            }}
                            yesIWantToUseGoogleMapApiInternals
                            onGoogleApiLoaded={({ map, maps }) => apiHasLoaded(map, maps)}
                        ></GoogleMapReact>
                    </div>
                    <div className="ride-booking-wrapper">
                        <Row>
                            <Col md={8}>
                                <div className="ride-booking-details">
                                    <div className="booking-header">
                                        <div className="ride-now">
                                            {t("RIDE_NOW")}
                                            <Toggle
                                                defaultChecked={isSwitchOn}
                                                icons={false}
                                                onChange={() => switch_onChange_handle()}
                                            />
                                        </div>
                                        <div className="control-btns">
                                            <Nav defaultActiveKey="/#" as="div">
                                                <h5
                                                    className={
                                                        methodkey === 1 ? "nav-link active" : "nav-link"
                                                    }
                                                    onClick={() => {
                                                        setMethodKey(1);
                                                    }}
                                                >
                                                    <img
                                                        src={
                                                            methodkey === 1
                                                                ? "/images/mark/location.png"
                                                                : "/images/mark/black_location.png"
                                                        }
                                                        width="14px"
                                                        height="14px"
                                                    ></img>
                                                    {t("Transfer")}
                                                </h5>
                                                <h5
                                                    className={
                                                        methodkey === 2 ? "nav-link active" : "nav-link"
                                                    }
                                                    onClick={() => {
                                                        setMethodKey(2);
                                                    }}
                                                >
                                                    <img
                                                        src={
                                                            methodkey === 2
                                                                ? "/images/mark/clock.png"
                                                                : "/images/mark/black_clock.png"
                                                        }
                                                        width="14px"
                                                        height="14px"
                                                    ></img>
                                                    {t("Hourly")}
                                                </h5>
                                            </Nav>
                                        </div>
                                    </div>
                                    <div className="ride-booking-data-wrapper">
                                        <div className="ride-booking-data">
                                            <div className="ride-booking-data-header">
                                                <div className={key == "searchall" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey("searchall");
                                                    }}
                                                >
                                                    Search All
                                                </div>
                                                <div className={key == "address" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey("address");
                                                    }}
                                                >
                                                    Address
                                                </div>
                                                <div className={key == "airport" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey("airport");
                                                    }}
                                                >
                                                    Airport
                                                </div>
                                                <div className={key == "landmark" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey("landmark");
                                                    }}
                                                >
                                                    Landmark
                                                </div>
                                            </div>
                                            <div className="ride-booking-data-inputs">
                                                <div className="ride-booking-data-input-wrapper pickup">
                                                        <div className="ride-booking-data-title">
                                                            <label className="title">{t("Pickup")}:</label>
                                                        </div>
                                                        <div className="ride-booking-data-input">
                                                            {mapApi ? (
                                                                <AutoComplete
                                                                    map={mapInstance}
                                                                    mapApi={mapApi}
                                                                    initialValue={selectedOption}
                                                                    setValue={setSelectedOption}
                                                                    addplace={addPickupPlace}
                                                                    searchkey={key}
                                                                    selectedType={callback}
                                                                    type={"pickup"}
                                                                />
                                                            ) : (
                                                                ""
                                                            )}
                                                        </div>
                                                    </div>
                                            </div>
                                            <span className="text-danger">{errors.pickup}</span>
                                            {key === "airport" ? (
                                                <div className="ride-booking-data-input airport">
                                                    <div className="d-flex justify-content-between">
                                                        <div className="ride-booking-data-inputs">
                                                            <input type="text" placeholder="Select airline"></input>
                                                        </div>
                                                        <div className="ride-booking-data-inputs">
                                                            <input
                                                                type="number"
                                                                placeholder="Flight number"
                                                            ></input>
                                                        </div>
                                                        <div className="ride-booking-data-inputs">
                                                            <input type="time" placeholder="arrival time"></input>
                                                        </div>
                                                    </div>
                                                </div>
                                            ) : (
                                                ""
                                            )}
                                        </div>
                                        <div>
                                            {stopVisible && stopFields.map((stops, index) => {
                                                { console.log('ssss', stops) }
                                                return (
                                                    <div className="ride-booking-data">
                                                        <div className="ride-booking-data-header">
                                                            <div className={stops.children.searchall ? "booking-type active" : "booking-type"}
                                                                onClick={() => {
                                                                    setNewStop('searchall', index)
                                                                }}
                                                            >
                                                                Search All
                                                            </div>
                                                            <div className={stops.children.address ? "booking-type active" : "booking-type"}
                                                                onClick={() => {
                                                                    setNewStop('address', index)
                                                                }}
                                                            >
                                                                Address
                                                            </div>
                                                            <div className={stops.children.airport ? "booking-type active" : "booking-type"}
                                                                onClick={() => {
                                                                    setNewStop('airport', index)
                                                                }}
                                                            >
                                                                Airport
                                                            </div>
                                                            <div className={stops.children.landmark ? "booking-type active" : "booking-type"}
                                                                onClick={() => {
                                                                    setNewStop('landmark', index)
                                                                }}
                                                            >
                                                                Landmark
                                                            </div>
                                                        </div>
                                                        <div className="ride-booking-data-inputs">
                                                            {stops.children.searchall ? (
                                                                <div
                                                                    className="stop d-flex align-items-center justify-content-between"
                                                                >
                                                                    <div className="stop-location w-100">
                                                                        <label className="title">
                                                                            {t("Stop-")}
                                                                            {index + 1}:
                                                                        </label>
                                                                        {mapApi ? (
                                                                            <AutoComplete
                                                                                map={mapInstance}
                                                                                mapApi={mapApi}
                                                                                value={stop}
                                                                                initialValue={stop[index]}
                                                                                setValue={setStop}
                                                                                addplace={addStopPlace}
                                                                                searchkey={'searchall'}
                                                                                id={index}
                                                                                type={"stop"}
                                                                            />
                                                                        ) : (
                                                                            ""
                                                                        )}
                                                                    </div>

                                                                    <div
                                                                        className="trash"
                                                                        onClick={() => deleteStop(index)}
                                                                    >
                                                                        <img
                                                                            src={Trash}
                                                                            alt="trash"
                                                                            width="24px"
                                                                            height="24px"
                                                                        />
                                                                    </div>
                                                                </div>
                                                            ) : (
                                                                ""
                                                            )}
                                                            {stops.children.address ? (
                                                                <div
                                                                    className="stop d-flex align-items-center justify-content-between"
                                                                >
                                                                    <div className="stop-location w-100">
                                                                        <label className="title">
                                                                            {t("Stop-")}
                                                                            {index + 1}:
                                                                        </label>
                                                                        {mapApi ? (
                                                                            <AutoComplete
                                                                                map={mapInstance}
                                                                                mapApi={mapApi}
                                                                                value={stop}
                                                                                initialValue={stop[index]}
                                                                                setValue={setStop}
                                                                                addplace={addStopPlace}
                                                                                searchkey={'address'}
                                                                                id={index}
                                                                                type={"stop"}
                                                                            />
                                                                        ) : (
                                                                            ""
                                                                        )}
                                                                    </div>

                                                                    <div
                                                                        className="trash"
                                                                        onClick={() => deleteStop(index)}
                                                                    >
                                                                        <img
                                                                            src={Trash}
                                                                            alt="trash"
                                                                            width="24px"
                                                                            height="24px"
                                                                        />
                                                                    </div>
                                                                </div>
                                                            ) : (
                                                                ""
                                                            )}
                                                            {stops.children.airport ? (
                                                                <div
                                                                    className="stop d-flex align-items-center justify-content-between"
                                                                >
                                                                    <div className="stop-location w-100">
                                                                        <label className="title">
                                                                            {t("Stop-")}
                                                                            {index + 1}:
                                                                        </label>
                                                                        {mapApi ? (
                                                                            <AutoComplete
                                                                                map={mapInstance}
                                                                                mapApi={mapApi}
                                                                                value={stop}
                                                                                initialValue={stop[index]}
                                                                                setValue={setStop}
                                                                                addplace={addStopPlace}
                                                                                searchkey={'airport'}
                                                                                id={index}
                                                                                type={"stop"}
                                                                            />
                                                                        ) : (
                                                                            ""
                                                                        )}
                                                                    </div>

                                                                    <div
                                                                        className="trash"
                                                                        onClick={() => deleteStop(index)}
                                                                    >
                                                                        <img
                                                                            src={Trash}
                                                                            alt="trash"
                                                                            width="24px"
                                                                            height="24px"
                                                                        />
                                                                    </div>
                                                                </div>
                                                            ) : (
                                                                ""
                                                            )}
                                                            {stops.children.landmark ? (
                                                                <div
                                                                    className="stop d-flex align-items-center justify-content-between"
                                                                >
                                                                    <div className="stop-location w-100">
                                                                        <label className="title">
                                                                            {t("Stop-")}
                                                                            {index + 1}:
                                                                        </label>
                                                                        {mapApi ? (
                                                                            <AutoComplete
                                                                                map={mapInstance}
                                                                                mapApi={mapApi}
                                                                                value={stop}
                                                                                initialValue={stop[index]}
                                                                                setValue={setStop}
                                                                                addplace={addStopPlace}
                                                                                searchkey={'landmark'}
                                                                                id={index}
                                                                                type={"stop"}
                                                                            />
                                                                        ) : (
                                                                            ""
                                                                        )}
                                                                    </div>

                                                                    <div
                                                                        className="trash"
                                                                        onClick={() => deleteStop(index)}
                                                                    >
                                                                        <img
                                                                            src={Trash}
                                                                            alt="trash"
                                                                            width="24px"
                                                                            height="24px"
                                                                        />
                                                                    </div>
                                                                </div>
                                                            ) : (
                                                                ""
                                                            )}
                                                        </div>

                                                        {stops.children.airport ? (
                                                            <div className="ride-booking-data-input airport">
                                                                <div className="d-flex justify-content-between">
                                                                    <div className="ride-booking-data-inputs">
                                                                        <input type="text" placeholder="Select airline"></input>
                                                                    </div>
                                                                    <div className="ride-booking-data-inputs">
                                                                        <input
                                                                            type="number"
                                                                            placeholder="Flight number"
                                                                        ></input>
                                                                    </div>
                                                                    <div className="ride-booking-data-inputs">
                                                                        <input type="time" placeholder="arrival time"></input>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            ""
                                                        )}
                                                    </div>
                                                )
                                            })}
                                        </div>
                                        <div className="ride-booking-data">
                                            <div className="ride-booking-data-header">
                                                <div className={key2 == "searchall2" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey2("searchall2");
                                                    }}
                                                >
                                                    Search All
                                                </div>
                                                <div className={key2 == "address2" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey2("address2");
                                                    }}
                                                >
                                                    Address
                                                </div>
                                                <div className={key2 == "airport2" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey2("airport2");
                                                    }}
                                                >
                                                    Airport
                                                </div>
                                                <div className={key2 == "landmark2" ? "booking-type active" : "booking-type"}
                                                    onClick={() => {
                                                        setKey2("landmark2");
                                                    }}
                                                >
                                                    Landmark
                                                </div>
                                            </div>
                                            <div className="ride-booking-data-inputs">
                                                {key2 === "searchall2" ? (
                                                    <div className="ride-booking-data-input-wrapper dropoff">
                                                        <div className="ride-booking-data-title">
                                                            <label className="title">{t("Dropoff")}:</label>
                                                        </div>
                                                        <div className="ride-booking-data-input">
                                                            {mapApi ? (
                                                                <AutoComplete
                                                                    map={mapInstance}
                                                                    mapApi={mapApi}
                                                                    initialValue={dropoff}
                                                                    setValue={setDropoff}
                                                                    addplace={addDropoffPlace}
                                                                    searchkey={key2}
                                                                    type={"dropoff"}
                                                                />
                                                            ) : (
                                                                ""
                                                            )}
                                                        </div>
                                                    </div>
                                                ) : (
                                                    ""
                                                )}
                                                {key2 === "address2" ? (
                                                    <div className="ride-booking-data-input-wrapper dropoff">
                                                        <div className="ride-booking-data-title">
                                                            <label className="title">{t("Dropoff")}:</label>
                                                        </div>
                                                        <div className="ride-booking-data-input">
                                                            {mapApi ? (
                                                                <AutoComplete
                                                                    map={mapInstance}
                                                                    mapApi={mapApi}
                                                                    initialValue={dropoff}
                                                                    setValue={setDropoff}
                                                                    addplace={addDropoffPlace}
                                                                    searchkey={key2}
                                                                    type={"dropoff"}
                                                                />
                                                            ) : (
                                                                ""
                                                            )}
                                                        </div>
                                                    </div>
                                                ) : (
                                                    ""
                                                )}
                                                {key2 === "airport2" ? (
                                                    <div>
                                                        <div className="ride-booking-data-input-wrapper dropoff">
                                                            <div className="ride-booking-data-title">
                                                                <label className="title">{t("Dropoff")}:</label>
                                                            </div>
                                                            <div className="ride-booking-data-input">
                                                                {mapApi ? (
                                                                    <AutoComplete
                                                                        map={mapInstance}
                                                                        mapApi={mapApi}
                                                                        initialValue={dropoff}
                                                                        setValue={setDropoff}
                                                                        addplace={addDropoffPlace}
                                                                        searchkey={key2}
                                                                        type={"dropoff"}
                                                                    />
                                                                ) : (
                                                                    ""
                                                                )}
                                                            </div>

                                                        </div>
                                                    </div>
                                                ) : (
                                                    ""
                                                )}
                                                {key2 === "landmark2" ? (
                                                    <div className="ride-booking-data-input-wrapper dropoff">
                                                        <div className="ride-booking-data-title">
                                                            <label className="title">{t("Dropoff")}:</label>
                                                        </div>
                                                        <div className="ride-booking-data-input">
                                                            {mapApi ? (
                                                                <AutoComplete
                                                                    map={mapInstance}
                                                                    mapApi={mapApi}
                                                                    initialValue={dropoff}
                                                                    setValue={setDropoff}
                                                                    addplace={addDropoffPlace}
                                                                    searchkey={key2}
                                                                    type={"dropoff"}
                                                                />
                                                            ) : (
                                                                ""
                                                            )}
                                                        </div>
                                                    </div>
                                                ) : (
                                                    ""
                                                )}
                                            </div>
                                            <span className="text-danger">{errors.dropoff}</span>
                                            {key2 === "airport2" ? (
                                                <div className="ride-booking-data-input airport">
                                                    <div className="d-flex justify-content-between">
                                                        <div className="ride-booking-data-inputs">
                                                            <input type="text" placeholder="Select airline"></input>
                                                        </div>
                                                        <div className="ride-booking-data-inputs">
                                                            <input
                                                                type="number"
                                                                placeholder="Flight number"
                                                            ></input>
                                                        </div>
                                                        <div className="ride-booking-data-inputs">
                                                            <input type="time" placeholder="arrival time"></input>
                                                        </div>
                                                    </div>
                                                </div>
                                            ) : (
                                                ""
                                            )}
                                        </div>
                                        <div className="addstop">
                                            {/* <div className="add-stop" onClick={() => addStop()}> */}
                                            <div className="add-stop" onClick={() => addFields(stopFields)}>

                                                <i className="fa fa-plus"></i>
                                                {t("Add_Stop")}
                                            </div>
                                        </div>
                                        {methodkey === 2 ? (
                                            <div className="ride-booking-data timing">
                                                <div className="hour-min-input">
                                                    <div className="hour-min">
                                                        <div className="hour-input">
                                                            <div className="hour-input__wrapper">
                                                                <label className="title">
                                                                    * Trip Duration Hours:
                                                                </label>
                                                                <input
                                                                    type="number"
                                                                    value={hours}
                                                                    onChange={(e) =>
                                                                        e.target.value >= 0 || ""
                                                                            ? setHours(e.target.value)
                                                                            : setHours(0)
                                                                    }
                                                                />
                                                            </div>
                                                            <div className="plus-minus">
                                                                <button
                                                                    className="minus"
                                                                    onClick={() => {
                                                                        parseInt(hours) > 0
                                                                            ? setHours(hours - 1)
                                                                            : setHours(0);
                                                                    }}
                                                                >
                                                                    <i className="fa fa-minus"></i>
                                                                </button>
                                                                <button
                                                                    className="plus"
                                                                    onClick={() => {
                                                                        setHours(hours + 1);
                                                                    }}
                                                                >
                                                                    <i className="fa fa-plus"></i>
                                                                </button>
                                                            </div>

                                                        </div>
                                                        <span className="text-danger">{errors.hours}</span>
                                                    </div>
                                                    <div className="hour-min">
                                                        <div className="hour-input">
                                                            <div className="hour-input__wrapper">
                                                                <label className="title">
                                                                    * Trip Duration Mins:
                                                                </label>
                                                                <input
                                                                    type="number"
                                                                    value={mins}
                                                                    onChange={(e) =>
                                                                        e.target.value >= 0 || ""
                                                                            ? setMins(e.target.value)
                                                                            : setHours(0)
                                                                    }
                                                                />
                                                            </div>
                                                            <div className="plus-minus">
                                                                <button
                                                                    className="minus"
                                                                    onClick={() => {
                                                                        parseInt(mins) > 0
                                                                            ? setMins(mins - 1)
                                                                            : setMins(0);
                                                                    }}
                                                                >
                                                                    <i className="fa fa-minus"></i>
                                                                </button>
                                                                <button
                                                                    className="plus"
                                                                    onClick={() => {
                                                                        setMins(mins + 1);
                                                                    }}
                                                                >
                                                                    <i className="fa fa-plus"></i>
                                                                </button>
                                                            </div>

                                                        </div>
                                                        <span className="text-danger">{errors.mins}</span>
                                                    </div>
                                                </div>
                                            </div>
                                        ) : (
                                            ""
                                        )}
                                    </div>
                                </div>
                            </Col>
                            <Col md={4}>
                                <div className="ride-booking-sidebar">
                                    {!isSwitchOn ? (
                                        <div className="ride-booking-input">
                                            <div className="title">{t("Pickup_date")}:</div>
                                            <div className="inputs">
                                                {/* <DatePicker
                                                onChange={datechange}
                                                initialDate={dayjs(startDate)}
                                                dateFormat="ddd, MMM DD, YYYY"
                                                selected={startDate}
                                                className="datePicker"
                                            /> */}
                                                <DateTimePicker
                                                    onChange={(value) => alert('New date is: ', value)}
                                                    value={new Date()}
                                                    disableClock="true"
                                                    calendarClassName="datePicker" />
                                                <img
                                                    src="/images/mark/calendar.png"
                                                    width="20px"
                                                    height="20px"
                                                />
                                                <span className="text-danger">
                                                    {errors.startDate}
                                                </span>
                                            </div>
                                        </div>) : ("")}
                                    {!isSwitchOn ? (
                                        <div className="ride-booking-input">
                                            <div className="title">{t("Pickup_time")}:</div>
                                            <div className="inputs">
                                                <DatePicker
                                                    showTimeOnly
                                                    selected={startTime}
                                                    initialDate={dayjs(startTime)}
                                                    onChange={timechange}
                                                />
                                                <img
                                                    src="/images/mark/black_clock.png"
                                                    width="20px"
                                                    height="20px"
                                                />
                                                <span className="text-danger">
                                                    {errors.startTime}
                                                </span>
                                            </div>
                                        </div>) : ("")}
                                    <div className="ride-booking-input">
                                        <div className="title">{t("Passengers")}</div>
                                        <div className="inputs body">
                                            <span className="count">{passenger}</span>
                                            <div className="btns">
                                                <button
                                                    type="button"
                                                    className="minus"
                                                    onClick={() => {
                                                        passenger > 0
                                                            ? setPassenger(passenger - 1)
                                                            : setPassenger(0);
                                                    }}
                                                >
                                                    <i className="fa-solid fa-minus"></i>
                                                </button>
                                                <button
                                                    type="button"
                                                    className="plus"
                                                    onClick={() => {
                                                        setPassenger(passenger + 1);
                                                    }}
                                                >
                                                    <i className="fa fa-plus"></i>
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="ride-booking-input">
                                        <div className="title" onClick={select_vehicle}>
                                            {t("Children")}
                                        </div>
                                        <div className="body inputs">
                                            <span className="count">{children}</span>
                                            <div className="btns">
                                                <button
                                                    type="button"
                                                    className="minus"
                                                    onClick={() => {
                                                        children > 0
                                                            ? setChildren(children - 1)
                                                            : setChildren(0);
                                                    }}
                                                >
                                                    <i className="fa fa-minus"></i>
                                                </button>
                                                <button
                                                    type="button"
                                                    className="plus"
                                                    onClick={() => {
                                                        setChildren(children + 1);
                                                    }}
                                                >
                                                    <i className="fa fa-plus"></i>
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="ride-booking-input">
                                        <div className="title">{t("Bags")}</div>
                                        <div className="body inputs">
                                            <span className="count">{bag}</span>
                                            <div className="btns">
                                                <button
                                                    type="button"
                                                    className="minus"
                                                    onClick={() => {
                                                        bag > 0 ? setBag(bag - 1) : setBag(0);
                                                    }}
                                                >
                                                    <i className="fa fa-minus"></i>
                                                </button>
                                                <button
                                                    type="button"
                                                    className="plus"
                                                    onClick={() => {
                                                        setBag(bag + 1);
                                                    }}
                                                >
                                                    <i className="fa fa-plus"></i>
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <h5 className="select-vehicle" onClick={handleSUbmit}>
                                    {t("Select_Vehicle")}
                                </h5>
                            </Col>
                        </Row>
                    </div>
                </Container>
            </div>
        </div>
    );
};

export { Home };
