import * as React from "react";
import * as ReactDOM from "react-dom";
import { ChartComponent, SeriesCollectionDirective, SeriesDirective, Inject, ColumnSeries, Legend, Tooltip, DataLabel } from '@syncfusion/ej2-react-charts';
import { setCurrencyCode } from '@syncfusion/ej2-base';
setCurrencyCode('EUR');
class Test extends React.Component {
    constructor() {
        super(...arguments);
        this.data = [
            { x: 1900, y: 4, y1: 2.6, y2: 2.8 }, { x: 1920, y: 3.0, y1: 2.8, y2: 2.5 },
            { x: 1940, y: 3.8, y1: 2.6, y2: 2.8 }, { x: 1960, y: 3.4, y1: 3, y2: 3.2 },
            { x: 1980, y: 3.2, y1: 3.6, y2: 2.9 }, { x: 2000, y: 3.9, y1: 3, y2: 2 }
        ];
        this.primaryxAxis = { edgeLabelPlacement: 'Shift', title: 'Years' };
        this.primaryyAxis = { labelFormat: 'c', title: 'Sales Amount in Millions' };
        this.marker = { dataLabel: { visible: true } };
        this.tooltip = { enable: true, format: '${point.x} : ${point.y}' };
    }
    render() {
        return <ChartComponent id='charts' primaryXAxis={this.primaryxAxis} primaryYAxis={this.primaryyAxis} title='Average Sales Comparison' tooltip={this.tooltip}>
  <Inject services={[ColumnSeries, Legend, Tooltip, DataLabel]}/>
  <SeriesCollectionDirective>
    <SeriesDirective dataSource={this.data} xName='x' yName='y' name='Product X' type='Column' marker={this.marker}>
    </SeriesDirective>
    <SeriesDirective dataSource={this.data} xName='x' yName='y1' name='Product Y' type='Column' marker={this.marker}>
    </SeriesDirective>
  </SeriesCollectionDirective>
</ChartComponent>;
    }
}
export {Test}